function Signup() {
  return (
    <div
      style={{
        padding: "40px",
        fontFamily: "Arial",
        background: "#f8fafc",
        minHeight: "100vh",
      }}
    >
      <h2>Create Account</h2>

      <input placeholder="Full Name" /><br /><br />
      <input placeholder="Gender" /><br /><br />
      <input type="date" /><br /><br />
      <input placeholder="Email" /><br /><br />
      <input placeholder="Username" /><br /><br />
      <input type="password" placeholder="Password" /><br /><br />
      <input placeholder="Phone Number" /><br /><br />
      <input placeholder="Alternative Phone Number" /><br /><br />

      <button
        style={{
          padding: "10px 24px",
          backgroundColor: "#16a34a",
          color: "white",
          border: "none",
          borderRadius: "6px",
        }}
      >
        Create Account
      </button>
    </div>
  );
}

export default Signup;
